def create_default_verifier(
    *,
    hs256_secret: Optional[str] = None,
    rs256_public_key: Optional[str] = None,
    hs256_issuer: Optional[str] = None,
    rs256_issuer: Optional[str] = None,
    hs256_audience: Optional[Union[str, Sequence[str]]] = None,
    rs256_audience: Optional[Union[str, Sequence[str]]] = None,
    require_claims: Optional[Sequence[str]] = ("exp",),
) -> JWTVerifier:
    configs: List[JWTKeyConfig] = []

    if hs256_secret:
        configs.append(
            JWTKeyConfig(
                alg="HS256",
                key=hs256_secret,
                issuer=hs256_issuer,
                audience=hs256_audience,
            )
        )

    if rs256_public_key:
        configs.append(
            JWTKeyConfig(
                alg="RS256",
                public_key=rs256_public_key,
                issuer=rs256_issuer,
                audience=rs256_audience,
            )
        )

    if not configs:
        raise JWTConfigurationError("At least one of hs256_secret or rs256_public_key must be provided")

    return JWTVerifier(
        configs=configs,
        allowed_algorithms=["HS256", "RS256"],
        require_claims=list(require_claims or []),
        default_options={"verify_signature": True, "verify_exp": True},
        reject_none_algorithm=True,
    )


def load_pem_file(path: str) -> str:
    with open(path, "r", encoding="utf-8") as f:
        return f.read()


def create_verifier_from_env() -> JWTVerifier:
    configs: List[JWTKeyConfig] = []

    hs256_secret = os.getenv("JWT_HS256_SECRET")
    if hs256_secret:
        configs.append(
            JWTKeyConfig(
                alg="HS256",
                key=hs256_secret,
                kid=os.getenv("JWT_HS256_KID"),
                issuer=os.getenv("JWT_HS256_ISSUER"),
                audience=os.getenv("JWT_HS256_AUDIENCE"),
                leeway=int(os.getenv("JWT_HS256_LEEWAY", "0")),
            )
        )

    rs256_public_key = os.getenv("JWT_RS256_PUBLIC_KEY")
    rs256_public_key_path = os.getenv("JWT_RS256_PUBLIC_KEY_PATH")
    if not rs256_public_key and rs256_public_key_path:
        rs256_public_key = load_pem_file(rs256_public_key_path)

    if rs256_public_key:
        configs.append(
            JWTKeyConfig(
                alg="RS256",
                public_key=rs256_public_key,
                kid=os.getenv("JWT_RS256_KID"),
                issuer=os.getenv("JWT_RS256_ISSUER"),
                audience=os.getenv("JWT_RS256_AUDIENCE"),
                leeway=int(os.getenv("JWT_RS256_LEEWAY", "0")),
            )
        )

    allowed_algorithms = os.getenv("JWT_ALLOWED_ALGORITHMS")
    if allowed_algorithms:
        allowed_algorithms = [a.strip() for a in allowed_algorithms.split(",") if a.strip()]
    else:
        allowed_algorithms = None

    require_claims = os.getenv("JWT_REQUIRE_CLAIMS")
    if require_claims:
        require_claims = [c.strip() for c in require_claims.split(",") if c.strip()]
    else:
        require_claims = ["exp"]

    if not configs:
        raise JWTConfigurationError("No JWT configuration found in environment")

    return JWTVerifier(
        configs=configs,
        allowed_algorithms=allowed_algorithms,
        require_claims=require_claims,
        default_options={"verify_signature": True, "verify_exp": True},
        reject_none_algorithm=True,
        strict_kid=os.getenv("JWT_STRICT_KID", "false").lower() in {"1", "true", "yes"},
    )